  (450, 'Quiron Latam en U$S', 5, 361, 115, 'Renta Mixta', 'Latinoamerica', 'Mediano Plazo', NULL, 2, '2008-09-30', 1, '588', 'El objetivo es capturar, mediante la inversión en activos de la Región Latinoamericana, una rentabilidad objetivo en el mediano plazo del 8% en dólares.', 1),
