  (799, 'SBS Patrimonio', 3, 347, 65, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 1, '2018-03-06', 1, '848', NULL, 1),
  (878, 'SBS Patrimonio II', 5, 347, 65, 'Renta Mixta', 'Global', 'Flexible', NULL, 1, '2019-05-24', 1, '1097', 'Sin datos', 1),
  (1601, 'SBS Patrimonio III', 5, 347, 65, 'Renta Mixta', 'Argentina', 'Corto Plazo', NULL, 1, '2025-01-02', 1, '1095', 'Sin datos', 0),
  (701, 'SBS Patrimonio IV', 5, 347, 65, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2017-09-15', 1, '847', 'El fondo tiene como objetivo maximizar retornos mediante la conformación de un portafolio de inversiones en moneda local que permita optimizar la relación riesgo-retorno con un horizonte de inversión de mediano/largo plazo.', 1),
  (1747, 'SBS Patrimonio IX', 5, 347, 115, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '2025-10-24', 1, '1542', 'Sin datos', 1),
  (1309, 'SBS Patrimonio V', 5, 347, 65, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '2022-02-18', 1, '1249', 'Obtener rentabilidad en Pesos', 1),
  (1312, 'SBS Patrimonio VI', 5, 347, 65, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '2022-03-30', 1, '1250', 'Obtener rentabilidad en Pesos', 1),
  (1739, 'SBS Patrimonio VIII', 5, 347, 65, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '2025-10-20', 1, '1541', 'Sin datos', 1),
  (507, 'SBS Pesos Plus', 3, 347, 115, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2011-10-03', 1, '643', 'El fondo tiene como objetivo obtener una renta en pesos superior a las tasas pasivas promedio del sistema financiero argentino. Como mínimo el 75% del patrimonio del FONDO será invertido en activos de renta fija e instrumentos representativos de ello, con oferta pública, emitidos y negociados en la República Argentina. Las características en la composición de la cartera del fondo buscan asumir una baja volatilidad y un perfil de riesgo del tipo conservador, orientado a inversores que privilegien menores plazos de liquidación.', 0),
  (620, 'SBS Renta Capital', 3, 347, 65, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 1, '2017-09-15', 1, '751', 'Tiene como objetivo maximizar el retorno en pesos asumiendo un riesgo moderado, recurriendo a la diversificación de cartera y el aprovechamiento de oportunidades de inversión en activos de renta fija y futuros. Las características en la composición de la cartera del fondo buscan asumir una volatilidad moderada.', 1),
  (889, 'SBS Renta Fija I FCIC', 9, 347, 65, 'Cerrado', 'Argentina', 'Largo Plazo', NULL, 1, '2019-07-10', 1, '1056', 'Sin datos', 999),
  (1237, 'SBS Renta Fija Total', 3, 347, 65, 'Renta Variable', 'Argentina', 'Mediano Plazo', NULL, 1, '2021-02-25', 1, '1096', 'Obtener la apreciación del valor del patrimonio del
