  (522, 'SBS Retorno Total', 7, 347, 115, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2017-09-15', 1, '644', NULL, 1),
  (549, 'SBS Tavelli Abierto Pymes', 6, 347, 65, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '2012-12-13', 1, '666', 'El Fondo Común de Inversión Tavelli Pymes es un vehículo de inversión orientado a canalizar el financiamiento de empresas y proyectos productivos de economías regionales, vinculados a pequeñas y medianas empresas.', 3),
  (523, 'SBS Tavelli Global', 5, 347, 65, 'Renta Mixta', 'Global', 'Flexible', NULL, 1, '2012-05-02', 1, '662', 'Tiene como objetivo maximizar el rendimiento de una cartera diversificada de renta fija, renta variable y tasas de interés.', 1),
  (199, 'SBS Tavelli Mix', 3, 347, 65, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '1997-08-01', 1, '251', 'Tiene como objetivo maximizar el rendimiento de un portfolio de renta fija en pesos de corto plazo, priorizando la preservación del capital y la liquidez en 24hs. con una reducida volatilidad.', 1),
  (147, 'SBS Tavelli Plus', 2, 347, 65, 'Renta Variable', 'Argentina', 'Largo Plazo', NULL, 1, '1996-09-13', 1, '181', 'Tiene como objetivo el crecimiento del capital, maximizando el retorno de las inversiones invirtiendo principalmente en acciones de empresas de riesgo moderado con cotización en el mercado argentino.', 1),
  (334, 'SBS Tavelli Renta', 3, 347, 65, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 1, '2001-10-04', 1, '446', 'Tiene como objetivo maximizar el rendimiento de un portfolio de renta fija conformado principalmente por títulos públicos locales, nominados en pesos y dólares.', 1),
  (143, 'Schroder Argentina', 3, 51, 65, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '1996-08-30', 1, '158', 'Proporcionar rentabilidad, principalmente a través de la inversión en instrumentos de renta fija pública y privada. El portfolio estará invertido en activos a tasa fija o variable según la coyuntura del mercado emitidos por el gobierno nacional, organismos públicos y emisiones empresariales con actividad en Argentina.', 1),
  (692, 'Schroder Balanceado', 5, 51, 65, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '2016-11-17', 1, '833', NULL, 1),
  (335, 'Schroder Capital Renta Fija', 3, 51, 65, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2001-10-15', 1, '429', 'Proporcionar rentabilidad, principalmente a través de la inversión en bonos latinoamericanos.', 1),
  (285, 'Schroder Corto Plazo', 3, 51, 65, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '1999-11-17', 1, '373', 'Proporcionar rentabilidad, principalmente a través de la inversión en instrumentos de renta fija pública y privada. El portfolio estará invertido en activos a tasa fija o variable emitidos por el gobierno nacional, organismos públicos y emisiones empresariales con actividad en Argentina.', 1),
  (1555, 'Schroder Crecimiento', 7, 51, 65, 'Renta Mixta', 'Argentina', 'Largo Plazo', NULL, 1, '2024-09-11', 1, '1528', 'El objetivo primario de la administración del fondo es obtener la apreciación del valor del patrimonio del fondo. A tal fin, el fondo invertirá en valores negociables, instrumentos financieros y otros activos financieros –de renta fija o variable, de carácter público o privado, nacionales o extranjeros– mencionados en este Capítulo 2 (con la denominación legal equivalente que corresponda en el caso de países distintos de la República Argentina), los que se considerarán activos autorizados.', 0),
  (1573, 'Schroder Crecimiento Dos', 7, 51, 65, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '2024-10-16', 1, '1529', 'El objetivo primario de la administración del fondo es obtener la apreciación del valor del patrimonio del fondo. A tal fin, el fondo invertirá en valores negociables, instrumentos financieros y otros activos financieros –de renta fija o variable, de carácter público o privado, nacionales o extranjeros– mencionados en este Capítulo 2 (con la denominación legal equivalente que corresponda en el caso de países distintos de la República Argentina), los que se considerarán activos autorizados.', 1),
  (1574, 'Schroder Crecimiento Tres', 7, 51, 65, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '2024-10-23', 1, '1530', 'El objetivo primario de la administración del fondo es obtener la apreciación del valor del patrimonio del fondo. A tal fin, el fondo invertirá en valores negociables, instrumentos financieros y otros activos financieros –de renta fija o variable, de carácter público o privado, nacionales o extranjeros– mencionados en este capítulo 2 (con la denominación legal equivalente que corresponda en el caso de países distintos de la República Argentina), los que se considerarán activos autorizados.', 1),
  (464, 'Schroder Desarrollo y Crecimiento PyMEs', 6, 51, 65, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2010-08-11', 1, '590', 'Proporcionar rentabilidad, principalmente a través de la inversión en instrumentos de renta fija o variable emitidos por empresas PyME, promoviendo el desarrollo y crecimiento del sector. El portfolio estará invertido en activos de tasa fija o variable según la coyuntura del mercado.', 1),
  (833, 'Schroder Income', 3, 51, 65, 'Renta Fija', 'Latinoamerica', 'Flexible', NULL, 2, '2018-08-30', 1, '1028', 'Sin datos', 2),
  (356, 'Schroder Infraestructura', 8, 51, 65, 'Renta Mixta', 'Argentina', 'Largo Plazo', NULL, 1, '2004-11-23', 1, '431', 'Proporcionar rentabilidad, principalmente a través de la inversión en instrumentos de renta fija pública y privada. El portfolio estará invertido en activos a tasa fija o variable según la coyuntura del mercado emitidos por el gobierno nacional, organismos públicos y emisiones empresariales con actividad en Argentina.', 1),
  (1343, 'Schroder Liquidez', 4, 51, 65, 'Plazo Fijo', 'Argentina', 'Mediano Plazo', NULL, 1, '2022-08-18', 1, '1248', 'Sin datos', 0),
  (688, 'Schroder Multiactivos', 5, 51, 65, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '2016-11-07', 1, '832', NULL, 1),
  (1410, 'Schroder Patrimonio', 3, 51, 65, 'Renta Fija', 'Argentina', 'Flexible', NULL, 1, '2023-05-04', 1, '1341', '''El objetivo primario es obtener la apreciación del valor del patrimonio del FONDO, mediante ingresos corrientes y ganancias de capital por la compra y venta de los ACTIVOS AUTORIZADOS. Al menos el SETENTA Y CINCO POR CIENTO (75%) del patrimonio neto del FONDO deberá invertirse en ACTIVOS AUTORIZADOS emitidos en el país exclusivamente en la Moneda del FONDO con las excepciones que establezcan las NORMAS (N.T. 2013 y mod.)''.', 1),
  (1439, 'Schroder Patrimonio Dos', 7, 51, 65, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '2023-10-06', 1, '1342', '''El objetivo primario es obtener la apreciación del valor del patrimonio del FONDO, mediante ingresos corrientes y ganancias de capital por la compra y venta de los ACTIVOS AUTORIZADOS. Son ACTIVOS AUTORIZADOS los valores negociables, instrumentos financieros y otros activos financieros de renta fija y/o renta variable (de carácter público o privado nacionales el objetivo primario es obtener la apreciación del valor del patrimonio del FONDO, mediante ingresos corrientes y ganancias de capital por la compra y venta de los ACTIVOS AUTORIZADOS. Son ACTIVOS AUTORIZADOS los valores negociables, instrumentos financieros y otros activos financieros de renta fija y/o renta variable (de carácter público o privado nacionales o extranjeros, en pesos o en moneda extranjera -inclusive activos dólar-linked-).', 1),
