  (587, 'Schroder Renta Global Tres', 7, 51, 65, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 1, '2014-04-01', 1, '689', 'Proporcionar rentabilidad, principalmente a través de la inversión en instrumentos de renta fija pública y privada.', 1),
  (1195, 'Schroder Renta Performance', 3, 51, 65, 'Renta Fija', 'Argentina', 'Flexible', NULL, 1, '2020-02-13', 1, '1107', 'Sin datos', 1),
  (609, 'Schroder Renta Plus', 3, 51, 65, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2015-04-06', 1, '717', 'El objetivo del Fondo es maximizar el rendimiento invirtiendo en activos de renta fija, depósitos en entidades financieras de reconocida solvencia, fideicomisos financieros y cauciones.', 1),
  (142, 'Schroder Renta Variable', 2, 51, 65, 'Renta Variable', 'Argentina', 'Largo Plazo', NULL, 1, '1996-08-29', 1, '153', 'Proporcionar rentabilidad mediante la inversión en empresas Argentinas con actividad local que coticen en la BCBA. El fondo buscará identificar los sectores y compañías de mayor potencial según la coyuntura de mercado.', 1),
  (555, 'Schroder Retorno Absoluto', 5, 51, 65, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '2013-03-22', 1, '677', 'Proporcionar rentabilidad, principalmente a través de la inversión en bonos soberanos y corporativos.', 1),
  (682, 'Schroder Retorno Total', 5, 51, 65, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 2, '2016-10-17', 1, '831', 'El objetivo del Fondo es maximizar el rendimiento invirtiendo en activos de renta fija en pesos siendo la nominación del Fondo en dólares.', 1),
  (1404, 'Schroder Retorno Total Cuatro', 5, 51, 65, 'Renta Mixta', 'Latinoamerica', 'Flexible', NULL, 2, '2023-04-27', 1, '1380', '''El objetivo primario es obtener la apreciación del valor del patrimonio del FONDO, mediante ingresos corrientes y ganancias de capital por la compra y venta de los ACTIVOS AUTORIZADOS. Al menos el SETENTA Y CINCO POR CIENTO (75%) del patrimonio neto del FONDO deberá invertirse en ACTIVOS AUTORIZADOS, emitidos y negociados en la República Argentina, o en los países que revistan el carácter de "Estado Parte" del MERCOSUR y en la REPÚBLICA DE CHILE.', 1),
  (752, 'Schroder Retorno Total Dos', 5, 51, 65, 'Renta Mixta', 'Latinoamerica', 'Flexible', NULL, 2, '2017-06-22', 1, '912', 'El objetivo del Fondo es maximizar el rendimiento invirtiendo en activos de renta fija en pesos siendo la nominación del Fondo en dólares.', 2),
  (860, 'SF Value', 5, 1, 115, 'Renta Mixta', 'Argentina', 'Largo Plazo', NULL, 1, '2019-03-01', 1, '1076', 'Sin datos', 1),
  (1250, 'SMR Fondo Comun de Inversion', 5, 22, 115, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2021-05-26', 1, '1184', 'Cobertura riesgo agrícola', 1),
  (783, 'SMSV Renta en Dolares', 3, 22, 65, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 2, '2017-10-17', 1, '986', NULL, 1),
  (696, 'ST Abierto Pymes', 6, 22, 65, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2017-09-05', 1, '850', 'ST Pymes es un fondo de renta fija con un horizonte de inversión de mediano plazo. Está nominado en pesos para las suscripciones, rescates y valuación de la cartera de inversiones. El objetivo del fondo es invertir en instrumentos locales con al menos un 75% de la cartera en activos destinados al financiamiento de PYMES conforme al inciso L del punto 35.8.1 del Reglamento General de la Actividad Aseguradora de la SSN.', 2),
  (1199, 'ST Infraestructura', 8, 22, 65, 'Renta Mixta', 'Argentina', 'Largo Plazo', NULL, 1, '2020-04-24', 1, '1125', 'Sin datos', 1),
  (567, 'ST Renta Fija', 3, 22, 65, 'Renta Fija', 'Argentina', 'Largo Plazo', NULL, 1, '2017-09-05', 1, '702', 'ST Renta Fija es un fondo de renta fija con un horizonte de inversión de mediano plazo. Está nominado en pesos para las suscripciones, rescates y valuación de la cartera de inversiones. El objetivo del fondo es invertir en renta fija soberana, provincial y corporativa maximizando el retorno total.', 1),
  (568, 'ST Renta Mixta', 5, 22, 65, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2017-09-05', 1, '703', 'ST Renta Mixta es un fondo que combina inversiones en activos de renta fija y renta mixta con un horizonte de mediano plazo. El objetivo del fondo es optimizar el rendimiento de los activos preservando el valor del capital en pesos. Busca ofrecer una cartera diversificada en cuanto a moneda y riesgo crediticio estructurándose sobre aquellos títulos de mayor liquidez. Está nominado en pesos para las suscripciones, rescates y valuación de la cartera de inversiones.', 1),
  (697, 'ST Retorno Total Dolares', 5, 22, 65, 'Renta Mixta', 'Argentina', 'Corto Plazo', NULL, 2, '2017-09-05', 1, '851', NULL, 2),
  (1222, 'ST Zero', 4, 22, 65, 'Plazo Fijo', 'Argentina', 'Corto Plazo', NULL, 1, '2020-11-02', 1, '1158', 'Sin datos', 0),
  (151, 'Super Ahorro $', 4, 49, 96, 'Plazo Fijo', 'Argentina', 'Corto Plazo', NULL, 1, '1996-11-05', 1, '145', 'Este Fondo invierte solamente en depósitos a la vista, cauciones y Plazos Fijos en bancos del Sistema Financiero Argentino. El Super Ahorro $ es una excelente alternativa presentando una baja volatilidad en el valor de cuotaparte del fondo. El Benchmark es 70% tasa de depósitos de Caja de Ahorro en $ y Plazos Fijos y 30% BADLAR.', 0),
  (519, 'Super Ahorro Plus', 4, 49, 96, 'Plazo Fijo', 'Argentina', 'Corto Plazo', NULL, 1, '2012-03-09', 1, '659', 'Este Fondo invierte solamente en depósitos a la vista, cauciones, Plazos Fijos en bancos del Sistema Financiero Argentino y deuda argentina de muy corto plazo. El Super Ahorro Plus es una excelente alternativa para aquellos clientes con perfil de riesgo conservador, que quieran invertir en deuda en pesos de corto plazo a través de obligaciones negociables, plazo fijos y títulos públicos , teniendo una liquidez en el día. El Benchmark es 50% tasa de depósitos de Caja de Ahorro en $ y Plazos Fijos y 50% BADLAR.', 0),
  (152, 'Super Ahorro U$S', 4, 49, 96, 'Plazo Fijo', 'Argentina', 'Corto Plazo', NULL, 2, '1996-11-05', 1, '146', NULL, 3),
  (341, 'Super Bonos', 3, 49, 96, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 1, '2002-09-03', 1, '464', 'Fondo de renta fija de mediano plazo con posición mayoritaria en activos con exposición a moneda extranjera. Principalmente, busca obtener ganancia de capital e ingreso a través de instrumentos nominados en dólares.', 2),
  (148, 'Superfondo Acciones', 2, 49, 96, 'Renta Variable', 'Argentina', 'Largo Plazo', NULL, 1, '1996-10-31', 1, '147', 'Busca superar el retorno de mediano/ largo plazo del índice Merval, que nuclea a las empresas más grandes del mercado Argentino.', 2),
  (382, 'Superfondo Acciones Brasil', 2, 49, 96, 'Renta Variable', 'Latinoamerica', 'Largo Plazo', NULL, 2, '2006-01-23', 1, '520', 'El objetivo del Superfondo Acciones Brasil es generar retornos absolutos invirtiendo en la principales compañías brasileras.', 5),
  (1596, 'Superfondo Ahorro en Dólares', 4, 49, 96, 'Plazo Fijo', 'Argentina', 'Corto Plazo', NULL, 2, '2024-12-06', 1, '1613', 'Sin datos', 0),
  (631, 'Superfondo Combinado', 5, 49, 96, 'Renta Mixta', 'Global', 'Flexible', NULL, 1, '2015-08-27', 1, '772', 'El Fondo invertirá en una cartera balanceada o mixta con una distribución objetiva de 85% en activos de Renta Fija y un 15% de activos en Renta Variable.', 2),
  (649, 'Superfondo Empresas Argentinas Abierto Pymes', 6, 49, 96, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '2016-02-25', 1, '777', NULL, 2),
