  (796, 'Superfondo Multiactivos Dólar', 5, 49, 96, 'Renta Mixta', 'Global', 'Largo Plazo', NULL, 180, '2018-02-06', 1, '1003', NULL, 5),
  (645, 'Superfondo Multirenta', 5, 49, 96, 'Renta Mixta', 'Global', 'Flexible', NULL, 1, '2016-02-10', 1, '790', NULL, 3),
  (149, 'Superfondo Renta $', 3, 49, 96, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 1, '1996-10-31', 1, '148', 'Fondo de renta fija de corto plazo con diversificación por moneda, plazo y emisor. Busca arbitrar activos acorde a su valuación relativa al mercado de deuda local, a través de deuda soberana, provincial, corporativa y depósitos a plazo fijo. Su baja volatilidad lo posiciona como una buena alternativa para inversores con perfil de riesgo bajo/moderado.', 2),
  (644, 'Superfondo Renta Balance', 5, 49, 96, 'Renta Mixta', 'Global', 'Flexible', NULL, 1, '2016-02-10', 1, '792', NULL, 3)
